export function parseR7106CSV(text: string): { data: R7106Record[]; warnings: string[] } {
  const warnings: string[] = []
  const lines = text.split(/\r?\n/).filter(l => l.trim())

  if (lines.length < 3) {
    warnings.push('File too short — expected at least 3 rows (title, section headers, column headers)')
    return { data: [], warnings }
  }

  // Find header row — look for MILL / WEEK / POL keywords
  let headerIdx = -1
  for (let i = 0; i < Math.min(5, lines.length); i++) {
    const lower = lines[i].toLowerCase()
    if (lower.includes('mill') && lower.includes('week')) {
      headerIdx = i
      break
    }
  }
  if (headerIdx < 0) {
    // Try first row that starts with MILL
    for (let i = 0; i < Math.min(5, lines.length); i++) {
      if (lines[i].trim().toLowerCase().startsWith('mill')) {
        headerIdx = i
        break
      }
    }
  }
  if (headerIdx < 0) {
    warnings.push('Could not find header row with MILL and WEEK columns')
    return { data: [], warnings }
  }

  const headers = lines[headerIdx].split(',').map(h => h.trim().toLowerCase())

  // Map column indices by name matching
  function findCol(...names: string[]): number {
    for (const name of names) {
      const idx = headers.indexOf(name)
      if (idx >= 0) return idx
    }
    // Partial match
    for (const name of names) {
      const idx = headers.findIndex(h => h.includes(name))
      if (idx >= 0) return idx
    }
    return -1
  }

  const colMap = {
    mill: findCol('mill', 'mill code'),
    millName: findCol('mill name', 'millname'),
    week: findCol('week'),
    tandem: findCol('tandem'),
    caneTons: findCol('cane'),
    polPercent: -1,
    brixPercent: -1,
    fibrePercent: -1,
    moisturePercent: -1,
    rvPercent: -1,
    sucrosePercent: -1,
    purityPercent: findCol('purity'),
    timeEfficiency: findCol('t-effcy', 'time eff'),
    polExtraction: findCol('extraction(pol)', 'pol extraction'),
    sucroseExtraction: findCol('extraction(sucr)', 'sucrose extraction'),
    crushRate: findCol('cane crush', 'crush rate', 'crush/hr'),
    fibreCrushRate: findCol('fibre crush'),
    weeklyRain: findCol('wkly rain', 'weekly rain'),
    ytdRain: findCol('ytd rain'),
  }

  // For % columns that appear after their ton columns, scan for pattern
  const caneCol = colMap.caneTons
  if (caneCol >= 0) {
    // In R7106, % columns follow tons columns: CANE | POL | % | BRIX | % | ...
    for (let c = caneCol + 1; c < Math.min(caneCol + 20, headers.length); c++) {
      const h = headers[c]
      if (h === '%' || h === '') continue
      if (h.includes('pol') && colMap.polPercent < 0) {
        colMap.polPercent = c + 1 // next col is %
      }
    }
  }

  const data: R7106Record[] = []
  let skipped = 0

  for (let i = headerIdx + 1; i < lines.length; i++) {
    const cols = lines[i].split(',').map(c => c.trim())
    const millVal = colMap.mill >= 0 ? Number(cols[colMap.mill]) : NaN
    const weekVal = colMap.week >= 0 ? Number(cols[colMap.week]) : NaN

    if (isNaN(millVal) || isNaN(weekVal) || millVal === 0 || weekVal === 0) {
      skipped++
      continue
    }

    const get = (idx: number) => {
      if (idx < 0 || idx >= cols.length) return 0
      const n = Number(cols[idx])
      return isNaN(n) ? 0 : Math.round(n * 100) / 100
    }

    data.push({
      mill: millVal,
      millName: colMap.millName >= 0 ? (cols[colMap.millName] || '') : (MILL_NAMES[millVal] || `Mill ${millVal}`),
      week: weekVal,
      tandem: get(colMap.tandem),
      caneTons: get(colMap.caneTons),
      polPercent: get(colMap.polPercent),
      brixPercent: get(colMap.brixPercent),
      nonPolPercent: 0,
      fibrePercent: get(colMap.fibrePercent),
      moisturePercent: get(colMap.moisturePercent),
      rvPercent: get(colMap.rvPercent),
      sucrosePercent: get(colMap.sucrosePercent),
      purityPercent: get(colMap.purityPercent),
      mjTonsPercent: 0,
      mjPolPercent: 0,
      mjBrixPercent: 0,
      mjPurity: 0,
      mjSucPurity: 0,
      bagTonsPercent: 0,
      bagPolPercent: 0,
      bagFibrePercent: 0,
      bagMoisturePercent: 0,
      polExtraction: get(colMap.polExtraction),
      sucroseExtraction: get(colMap.sucroseExtraction),
      rvPolPercent: 0,
      crushRate: get(colMap.crushRate),
      fibreCrushRate: get(colMap.fibreCrushRate),
      timeEfficiency: get(colMap.timeEfficiency),
      millingHoursPercent: 0,
      mechStopPercent: 0,
      noCaneStopPercent: 0,
      opStopPercent: 0,
      weeklyRain: get(colMap.weeklyRain),
      ytdRain: get(colMap.ytdRain),
    })
  }

  if (skipped > 0) {
    warnings.push(`Skipped ${skipped} rows with invalid mill/week values`)
  }
  warnings.push(`Parsed ${data.length} records from ${new Set(data.map(d => d.mill)).size} mills`)

  return { data, warnings }
}
